// ── Assembled export ──────────────────────────────────────────────────────────
export const TERRITORY_DUNGEONS = [T1_DUNGEONS, T2_DUNGEONS, T3_DUNGEONS, T4_DUNGEONS];

// Returns dungeon with custom layout from localStorage if saved, otherwise default
export function getDungeonWithLayout(territory, dungeonLevel) {
  const tArr = TERRITORY_DUNGEONS[territory];
  if (!tArr) return null;
  const dIdx = dungeonLevel - 1;
  const base = tArr[dIdx];
  if (!base) return null;
  const key = `dungeon_layout_t${territory}_d${dIdx}`;
  const raw = typeof window !== "undefined" ? localStorage.getItem(key) : null;
  if (raw) {
    try {
      const custom = JSON.parse(raw);
      return { ...base, buildings: custom };
    } catch {}
  }
  return base;
}
